Code.Terraform:
```hcl
# SNSトピックポリシーをアカウントに制限する（公開しない）
resource "aws_sns_topic_policy" "<example_resource_name>" {
  arn    = "<TOPIC_ARN>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Action    = "sns:Publish"
      Resource  = "<TOPIC_ARN>"
      Principal = { AWS = "arn:aws:iam::<ACCOUNT_ID>:root" } # 重大: パブリックアクセスを削除するためにプリンシパルをアカウントに制限する
    }]
  })
}
```
